                                            </label>
                                        </div>
                                        <div class="form-group mb-2" v-if="sitem.CORE_CONFIG_KEY == 'CustomDate'">
                                            <label>
                                                <b>{{ $t(sitem.CORE_CONFIG_KEY) }}:</b> {{ SplitDropDownValue(sitem) }}
                                            </label>
                                        </div>
                                        <div class="form-group mb-2" v-if="sitem.CORE_CONFIG_KEY == 'CLBankingDays'">
                                            <label>
                                                <b>{{ $t(sitem.CORE_CONFIG_KEY) }}:</b> {{ sitem.CORE_CONFIG_VALUE }}
                                            </label>
                                        </div>
                                        <div class="form-group mb-2" v-if="sitem.CORE_CONFIG_KEY == 'InvoiceType'">
                                            <label>
                                                <b>{{ $t(sitem.CORE_CONFIG_KEY) }}:</b> {{
                                                    GetInvoiceType(sitem.CORE_CONFIG_VALUE) != null ?
                                                        InvoiceType : '--' }}
                                            </label>
                                        </div>
                                        <div class="form-group mb-2"
                                            v-if="sitem.CORE_CONFIG_KEY == 'WorkdayInvoiceType'">
                                            <label>
                                                <b>{{ $t(sitem.CORE_CONFIG_KEY) }}:</b> {{
                                                    GetTemplateListBySetupId(sitem.CORE_CONFIG_VALUE)
                                                        != null ? TemplateName : '--' }}
                                            </label>
                                        </div>

                                    </div>
                                </div>
                            </div>
                        </div>
                       
                        
                    </div>
                </div>
            </div>
        </div>
        <AddClientAddressModal v-if="IsClientAddress" :IsClient="IsClient" :ClientId="ClientId"
            @ClosePopUp="ClosePopUp">
        </AddClientAddressModal>
        <ClientConfigurationData v-if="IsClientConfiguration" :ClientId="ClientId"
            @CloseConfigurationPopUp="CloseConfigurationPopUp"></ClientConfigurationData>
        <NewClientPopup v-if="IsNewClient" @onCancel="onCancel"></NewClientPopup>
        <AssociateContact v-if="OpenAssociateContact" :UserId="ClientId" @CloseAssociatePopup="CloseAssociatePopup">
        </AssociateContact>
        <AddCommunication v-if="IsAddCommunication" :IsClient="IsClient" :ClientId="UserId"
            @CloseAddCommuniction="CloseAddCommuniction"></AddCommunication>
        <AddClientNote v-if="IsAddNote" @CloseNotePopup="CloseNotePopup"></AddClientNote>
        <ContactNumberPopup v-if="IsContactNumber" :UserId="ClientId" :IsClient="IsClient"></ContactNumberPopup>
    </div>
</template>
<script>
import DataService from '../../../services/DataService';
import AddClientAddressModal from './AddClientAddressModal.vue';
import ClientConfigurationData from './ClientConfigurationData.vue';
import NewClientPopup from './NewClientPopup.vue';
import AssociateContact from './AssociateContacts.vue';
import AddCommunication from './AddCommunication.vue';
import AddClientNote from './AddClientNote.vue';
import ContactNumberPopup from './ContactNumberPopup.vue';
import VueApexCharts from 'vue-apexcharts';
export default {
    components: { AddClientAddressModal, ClientConfigurationData, NewClientPopup, AssociateContact, AddCommunication, AddClientNote, ContactNumberPopup, VueApexCharts },
    props: {
        ClientData: {
            type: Object,
            required: true
        },
        UserId: {
            type: Number
        },
        IsClient: {
            type: String
        }
    },
    data() {
        return {
            containerName: null,
            blobUrl: '',
            IsAddNote: false,
            IsAddCommunication: false,
            IsClientAddress: false,
            OpenAssociateContact: false,
            IsNewClient: false,
            ClientId: 0,
            IsClient: 'Client',
            moduleCode: 'Billing',
            AddressList: [],
            IsClientConfiguration: false,
            ModuleId: 0,
            StorageKeys: [],
            totalInvoicesIssued: '00.00',
            totalamountbilled: '00.00',
            totalamountpaid: '00.00',
            TotalAmountDue: '00.00',
            totaloverdueamount: '00.00',
            InvoiceData: [],
            searchCondition: '',
            PageSize: 10,
            statusId: '',
            PageNumber: 1,
            isPaged: 1,
            TotalPages: 0,
            ListingData: [],
            EmailData: [],
            LogginUserId: null,
            RoleName: '--',
            TaxJudrisdictionName: '--',
            NoteData: [],
            CompanyId: null,
            NoteObj: null,
            AccountName: '',
            ClientOwnerName: '--',
            clientTypeName: '--',
            TimeZoneName: '--',
            MobileNumber: '--',
            ImagePath: '',
            CurrencyCode: '',
            FormSchema: [],
            getInitialsName: '',
            IsContactNumber: false,
            TemplateName: '',
            InvoiceType: '',
            GetInvoicedata: [],
            series: [],
            isBillingType:false,
            BarChartData:[],
            chartOptions: {
                chart: {
                    type: 'bar',
                    stacked: false,
                    toolbar: { show: false }
                },
                plotOptions: {
                    bar: {
                        horizontal: false,
                        columnWidth: '55%'
                    }
                },
                xaxis: {
                    categories: [],
                    title: {
                        text: 'Work Date'
                    }
                },
                yaxis: {
                    title: {
                        text: 'Count'
                    }
                },
                legend: {
                    position: 'top'
                },
                dataLabels: {
                    enabled: false
                },
                tooltip: {
                    shared: true,
                    intersect: false
                }
            },
            NoteObj:null,
            AccountName:'',
            ClientOwnerName:'--',
            clientTypeName:'--',
            TimeZoneName:'--',
            MobileNumber:'--',
            ImagePath:'',
            CurrencyCode:'PKR' ,
            FormSchema:[],
            getInitialsName:'',
            IsContactNumber:false,
            isCheckExtraFeatureUSICBILLING:false
        }
    },
    created() {
        debugger
        var ths = this;
        ths.containerName = ths.GetUserInfo.ContainerName;
        ths.LogginUserId = ths.GetUserInfo.ID;
        ths.CompanyId = ths.GetUserInfo.CompanyId;
        ths.CurrencyCode = ths.GetUserInfo.Currency.replace(/[()]/g, '');
        ths.isBillingType = localStorage.getItem("billingType") === "USIC";
        ths.CheckFeaturesForCompany("USICBILLING");
        ths.getClientDetailData();
        ths.GetBlobUrl();
        ths.GetWidgetData();
        ths.GetAddressList();
        ths.GetModuleIdByModuleName();
        ths.GetContactList();
        ths.GetCommunicationList();
        ths.NoteListing();
        ths.ContactNumber();
        ths.GetWorkdateStatusData();
    },
    methods: { 
        CheckFeaturesForCompany: async function (type) {
            //debugger;
            var vm = this;
            var appendingUrl = `featureCode=${type}`;
            await DataService.CheckExtraFeatures(appendingUrl).then(function (response) {
               // debugger;
                if(type == 'USICBILLING'){
                    if (response.data == true) {
                         vm.isCheckExtraFeatureUSICBILLING = true;
                    } else {
                         vm.isCheckExtraFeatureUSICBILLING = false;
                    }
                //}
                //else if(type == 'UTILITY_BILLING'){
                    //if (response.data == true) {
                        // vm.isCheckExtraFeatureUtilityBilling = true;
                    //} else {
                         //vm.isCheckExtraFeatureUtilityBilling = false;
                    //}
                }
               
            });
        }, 
        getClientDetailData() {
            var ths = this;
            var url = `id=${ths.$route.params.id}&moduleName=Company&subModuleCode=Client`;
            DataService.GetDynamicViewList(url).then(function (response) {
                if (response != null && response.data != null) {
                    ths.FormSchema = response.data.LEFTDATA;
                    const firstNameField = ths.FormSchema.find(field => field.name === 'first_name');
                    const lastNameField = ths.FormSchema.find(field => field.name === 'last_name');
                    const accountField = ths.FormSchema.find(field => field.name === 'account_name');
                    const fullName = `${firstNameField?.value || ''} ${lastNameField?.value || ''}`.trim();
                    if (accountField) {
                        accountField.value = fullName;
                    }
                    ths.GetBlobUrl();
                }
            });
        },
        GetWorkdateStatusData() {
            var ths = this;
            var url = `ClientId=${ths.$route.params.id}`;
            DataService.GetWorkdateStatusData(url).then(function (response) {
                if (response.data.status == 'Success') {                    
                    var JsonData = JSON.parse(response.data.result);
                    var NewJsonData = JSON.parse(JsonData[0]);
                    if (NewJsonData.Data.length > 0) {
                        ths.BarChartData=NewJsonData.Data;
                        if (NewJsonData.Data && NewJsonData.Data.length > 0) {
                            ths.prepareChartData(NewJsonData.Data);
                        }
                    }

                }
            });
        },
        prepareChartData(data) {
            const categories = data.map(item => item.workdate); 
            // already in YYYY-MM-DD format ✔
            // ✅ MAKE IT REACTIVE
            this.$set(this.chartOptions.xaxis, 'categories', categories);
            this.series = [
                { name: 'FLAGGED', data: data.map(i => i.FLAGGED) },
                { name: 'BANKED', data: data.map(i => i.BANKED) },
                { name: 'SUPPRESSED', data: data.map(i => i.SUPPRESSED) },
                { name: 'DONOTBILL', data: data.map(i => i.DONOTBILL) },
                { name: 'UNPROCESSED', data: data.map(i => i.UNPROCESSED) },
                { name: 'PROCESSED', data: data.map(i => i.PROCESSED) }
            ];
            // ✅ FORCE ApexCharts to update X-axis
            this.$refs.workDateChart.updateOptions({
                xaxis: {
                    type: 'category',
                    categories: categories
                }
            });
        },

        ContactNumber: function () {
            var vm = this;
            vm.isLoading = true;
            var params = `pageNum=${vm.PageNumber}&pageSize=${vm.PageSize}&sortBy=&sortExp=&userId=${vm.UserId}`;
            DataService.GetUserPhoneList(params).then(function (response) {
                var PhoneNumberData = JSON.parse(response.data).data;
                vm.MobileNumber = PhoneNumberData.length > 0 ? PhoneNumberData.map(x => x.user_phone).join(',') : '--';
            })
        },
        GetCommunicationList: function () {
            var vm = this;
            vm.isLoading = true;
            var params = `pageNum=${vm.PageNumber}&pageSize=${vm.PageSize}&sortBy=&sortExp=&userId=${vm.UserId}`;
            DataService.GetUserEmailList(params).then(function (response) {
                var Data = JSON.parse(response.data);
                vm.EmailData = Data.data;
            })
        },
        GetWidgetData() {
            var vm = this;
            var url = `ClientId=${vm.UserId}&userAddressId=0`;
            DataService.GetClientWidgetData(url).then((response) => {
                if (response.data != null) {
                    if (response.data.result.DATA != null && response.data.result.DATA != '') {
                        vm.totalInvoicesIssued = response.data.result.DATA.Total_invoice_issued == 0 || response.data.result.DATA.Total_invoice_issued == null ? vm.totalInvoicesIssued : response.data.result.DATA.Total_invoice_issued;
                        vm.totalamountbilled = response.data.result.DATA.Total_amount_bill == 0 || response.data.result.DATA.Total_amount_bill == null ? vm.totalamountbilled : response.data.result.DATA.Total_amount_bill;
                        vm.totalamountpaid = response.data.result.DATA.Total_amount_paid == 0 || response.data.result.DATA.Total_amount_paid == null ? vm.totalamountpaid : response.data.result.DATA.Total_amount_paid;
                        vm.totaloverdueamount = response.data.result.DATA.Total_over_due_amount == 0 || response.data.result.DATA.Total_over_due_amount == null ? vm.totaloverdueamount : response.data.result.DATA.Total_over_due_amount;
                        vm.TotalAmountDue = response.data.result.DATA.Total_amount_due == 0 || response.data.result.DATA.Total_amount_due == null ? vm.TotalAmountDue : response.data.result.DATA.Total_amount_due;
                    }
                    if (response.data.result.INVOICE_DATA != null && response.data.result.INVOICE_DATA != '') {
                        vm.InvoiceData = response.data.result.INVOICE_DATA;
                        vm.InvoiceData.forEach((item) => {
                            item.bill_due_date = new Date(item.bill_due_date);
                            item.bill_issue_date = new Date(item.bill_issue_date);
                            item.bill_date_to = new Date(item.bill_date_to);
                        })
                    }
                }
            });
        },
        GetContactList() {
            var vm = this;
            var params = `clientId=${vm.UserId}&pageSize=${vm.PageSize}&pageNum=${vm.PageNumber}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}`;
            if (!vm.isBlank(this.searchCondition)) {
                params += `&search=${this.searchCondition}`;
            }
            DataService.ListAdditionalNewContact(params).then(function (response) {
                if (response.data) {
                    if (response.data.length > 0) {
                        vm.ListingData = response.data;
                        vm.TotalRecords = response.data[0].TOTALRECORDS;
                        vm.noRecord = false;

                    } else {
                        vm.ListingData = [];
                        vm.noRecord = true;
                        vm.TotalRecords = 0;
                    }
                } else {
                    vm.noRecord = true;
                    vm.ListingData = [];
                    vm.TotalRecords = 0
                }
            });
        },
        async GetAddressList() {
            var vm = this;
            var url = `userId=${vm.UserId}&userAddressId=0`;
            await DataService.GetAdditionalAddressList(url).then((response) => {
                if (response.data != null) {
                    vm.AddressList = [];
                    if (response.data.result.length > 0) {
                        vm.AddressList = response.data.result;
                    }
                }
            });
        },
        GetModuleConfigurationKeys: async function (item) {
            var ths = this;
            var params = 'moduleId=' + ths.ModuleId;
            await DataService.GetConfigurationkeysData(params).then(function (response) {
                if (response != null && response.data != null) {
                    ths.StorageKeys = response.data.StorageKeys;
                    var ConfigData = ths.StorageKeys.find(x => x.CORE_CONFIG_KEY == 'SelectSetup');
                    ths.LoadTemplateBySetupId(ConfigData.CORE_CONFIG_VALUE);
                }
            });
        },
        LoadTemplateBySetupId: async function (SetupId) {
            var vm = this;
            var params = `SetupId=${SetupId}`;
            await DataService.LoadTemplateBySetupId(params).then(function (response) {
                if (response.data.length > 0) {
                    vm.GetInvoicedata = response.data
                }
            });
        },
        async GetModuleIdByModuleName() {
            var vm = this;
            var params = `moduleName=${vm.moduleCode}`;
            await DataService.GetModuleIdByModuleName(params).then(function (response) {
                if (response != null && response.data != null) {
                    vm.ModuleId = response.data;
                    vm.GetModuleConfigurationKeys()
                }
            });
        },
        GetBlobUrl: function () {
            var ths = this;
            ths.isLoading = true;
            DataService.GetBlobUrl().then((response) => {
                var url = response.data[0].CONFIG_DATA_VALUE;
                if (ths.ClientData.clientdetail.avatar == null) {
                    ths.blobUrl = '';
                    const first = ths.ClientData.clientdetail.first_name ? ths.ClientData.clientdetail.first_name.trim() : '';
                    const last = ths.ClientData.clientdetail.last_name ? ths.ClientData.clientdetail.last_name.trim() : '';
                    if (!first && last) {
                        ths.getInitialsName = last.substring(0, 2).toUpperCase();
                    } else if (!last && first) {
                        ths.getInitialsName = first.substring(0, 2).toUpperCase();
                    } else if (first && last) {
                        ths.getInitialsName = (first.charAt(0) + last.charAt(0)).toUpperCase();
                    } else {
                        ths.getInitialsName = '--';
                    }
                }
                else {
                    const attachments = JSON.parse(this.ClientData.clientdetail.avatar);
                    const imagePath = attachments[0].AttachmentPath;
                    ths.blobUrl = url + this.containerName + '/' + imagePath;
                }
                ths.isLoading = false;
            })
        },
        ClosePopUp() {
            var ths = this;
            ths.IsClientAddress = false;
            ths.GetAddressList();
        },
        AddClientAddress() {
            var ths = this;
            ths.ClientId = ths.UserId;
            ths.IsClientAddress = true;
        },
        AddClientConfiguration() {
            var ths = this;
            ths.ClientId = ths.UserId;
            ths.IsClientConfiguration = true;
        },
        CloseConfigurationPopUp() {
            var ths = this;
            ths.GetModuleIdByModuleName();
            ths.IsClientConfiguration = false;
        },
        EditClient() {
            var ths = this;
            ths.IsNewClient = true;
        },
        onCancel() {
            var ths = this;
            ths.IsNewClient = false;
        },
        AssociateContact() {
            var ths = this;
            ths.ClientId = ths.UserId;
            ths.OpenAssociateContact = true;
        },
        CloseAssociatePopup() {
            var ths = this;
            ths.GetContactList();
            ths.OpenAssociateContact = false;
        },
        AddCommunication() {
            var ths = this;
            ths.IsAddCommunication = true;
        },
        CloseAddCommuniction() {
            var ths = this;
            ths.GetCommunicationList();
            ths.IsAddCommunication = false;
        },
        ClientMessage() {

        },
        async ClientDisable(val, type) {
            var vm = this;
            vm.isLoading = true;
            if (val != null) {
                if (type == 'Disable') {
                    vm.confirmR(vm.$t("ConfirmInactiveRecord"), true, (vm.$t("Disable") + "  " + vm.$t("Client")), function () {
                        var url = `ids=${val}&tablename=TALYGEN_company_client_New&primaryKey=user_id`;
                        DataService.Delete(url).then(async function (response) {
                            if (response.status == 200) {
                                vm.ShowAlert(vm.$t("RecordUpdatedSuccessfully"), "success", vm.$t('Alert'));
                                await vm.$parent.GetClientDetailByClientId(val)
                                vm.getClientDetailData();
                            }
                            else {
                                vm.ShowAlert(vm.$t('DeletedError', [vm.$t('TrainingFeedback')]), "Success", true, vm.$t("Alert"));
                            }
                        });
                    });
                } else {
                    vm.confirmR(vm.$t("ConfirmActiveRecord"), true, (vm.$t("Disable") + "  " + vm.$t("Client")), function () {
                        var url = `ids=${val}&tablename=TALYGEN_company_client_Status&primaryKey=user_id`;
                        DataService.Delete(url).then(async function (response) {
                            if (response.status == 200) {
                                vm.ShowAlert(vm.$t("RecordUpdatedSuccessfully"), "success", vm.$t('Alert'));
                                await vm.$parent.GetClientDetailByClientId(val)
                                vm.getClientDetailData();
                            }
                            else {
                                vm.ShowAlert(vm.$t('DeletedError', [vm.$t('TrainingFeedback')]), "Success", true, vm.$t("Alert"));
                            }
                        });
                    });
                }
            }
            else {
                vm.ShowAlert(vm.$t("Selectanyrecordtodelete"));
            }
            vm.isLoading = false;
        },
        AddNotes() {
            var ths = this;
            ths.NoteObj = null;
            ths.IsAddNote = true;
        },
        CloseNotePopup() {
            var ths = this;
            ths.NoteListing();
            ths.IsAddNote = false;
        },
        NoteListing() {
            var ths = this;
            ths.NoteData = [];
            var ApiURL = `id=${this.$route.params.id}&refId=${this.$route.params.id}&moduleName=Company&subModuleCode=Client`;
            DataService.NoteListing(ApiURL).then(response => {
                if (response.data.data.length > 0) {
                    response.data.data.forEach(item => {
                        item.note_date = new Date(item.note_date);
                        ths.NoteData.push(item);
                    })

                } else {
                    ths.NoteData = [];
                }
            })
        },
        getIconClass(type) {
            switch (type) {
                case 'HomeAddress':
                    return 'fa fa-home';
                case 'OfficeAddress':
                    return 'fa fa-building';
                case 'SecondaryAddress':
                    return 'fa fa-address-card';
                default:
                    return 'fa fa-address-card';
            }
        },
        formatFullAddress(item) {
            return [
                item.user_address_1,
                item.user_address_2,
                item.user_state,
                item.country_name,
                item.user_zipcode
            ]
                .filter(part => part && part.trim() !== '')
                .join(', ');
        },
        OpenContatNumber() {
            var ths = this;
            ths.ClientId = ths.UserId;
            ths.IsContactNumber = true;
        },
        DeAssociateContact: async function (event) {
            var vm = this;
            var data = [];
            var statusCodeId = event;
            var dataObject = {
                id: statusCodeId,
                userId: vm.UserId,
                isfor: "DeAssociate"
            };
            data.push(dataObject);
            if (data.length > 0) {
                await vm.confirmR(vm.$t("ContactConfirmDelete"), true, (vm.$t("Delete")), async function () {
                    var params = JSON.stringify(data);
                    DataService.SubmitAdditionalNewContacts(params).then((response) => {
                        if (response.data.Status == 'Success') {
                            vm.ShowAlert(vm.$t("ContactsDeletedSuccessfully"), "success", true, vm.$t("Alert"));
                            vm.GetContactList();
                        }
                        else {
                            vm.ShowAlert(vm.$t("AddedError", [vm.$t("Contacts")]), "failure", true, vm.$t("Alert"));
                        }
                    });
                });
            } else {
                vm.ShowAlert(vm.$t("PleaseSelectAnyRecordsForFurther"), "warning", true, vm.$t("Alert"));
            }
        },
        DropDownValue(data) {
            var JsonData = JSON.parse(data.SELECT_OPTIONS);
            var Value = JsonData.find(x => x.value == data.CORE_CONFIG_VALUE);
            return Value.name;
        },
        SplitDropDownValue(data) {
            var JsonData = data.CORE_CONFIG_OPTIONS.split('^');;
            var Value = JsonData.find(x => x == data.CORE_CONFIG_VALUE);
            return Value;
        },
        GetTemplateListBySetupId: async function (SetupId) {
            var vm = this;
            var params = `SetupId=${SetupId}`;
            await DataService.GetTemplateListBySetupId(params).then(function (response) {
                if (response.data.length > 0) {
                    var data = response.data.find(x => x.INVOICE_TYPE_ID == SetupId);
                    vm.TemplateName = data.NAME;
                }
                else {
                    vm.TemplateName = '--';
                }
            });
        },
        GetInvoiceType: async function (SetupId) {
            var vm = this;
            if (vm.GetInvoicedata.length > 0) {
                var data = vm.GetInvoicedata.find(x => x.Value == SetupId);
                vm.InvoiceType = data.Name;
            }
            else {
                vm.InvoiceType = '--';
            }
        },
        formatDate(dateInput) {
            if (!dateInput) return '--';

            const date = new Date(dateInput);

            return date.toLocaleDateString('en-US', {
                month: 'long',
                day: 'numeric',
                year: 'numeric'
            });
        },
        SummaryInvoice(item) {
            debugger
            const url = `/InvoiceReport/SummaryInvoice?billId=${encodeURIComponent(item.bill_id)}`;
            window.open(url, '_blank');           
        },

    }
}
</script>
