    methods: {
        async checkRatePrivilege(controllerName, actionName, onSuccess) {
            var vm = this;
            var privilegeParams = `controller=${controllerName}&action=${actionName}`;
            try {
                const response = await DataService.CheckPrivilege(privilegeParams);
                if (!response.data) {
                    vm.ShowAlert(vm.$t('NotAuthorizedSection'), "failure", true, "Alert");
                    return;
                }

                if (typeof onSuccess === 'function') {
                    await onSuccess();
                }
            } catch (error) {
                console.log('Error in checkRatePrivilege:', error);
            }
        },

UpdateCopyRateSchedule() {
    debugger;
    
    if (!this.selectedRateIds || this.selectedRateIds.length === 0) {
        this.ShowAlert(
            this.$t("PleaseSelectAnyRecordsForFurther"),
            "warning",
            true,
            this.$t("Alert")
        );
        return;
    }
    
    const selectedRows = this.RateScheduledeListing.filter(x =>
        this.selectedRateIds.includes(x.RATE_SCHEDULE_ID)
    );
    const utilityNames = [...new Set(selectedRows.map(row => row.UTILITY_NAME))];
    
    const jsonPayload = selectedRows.map(row => ({
        RateScheduleId: row.RATE_SCHEDULE_ID,
        ClientId: row.CLIENT_ID,
        WorkCodeId: row.WORKCODE_ID,
        UtilityId: row.UTILITY_ID,
        State: row.STATE_CODE,
        StartDate: row.New_Start_Date,
        EndDate: row.New_End_Date,
        Rate: row.New_Rate,
        Comment: row.COMMENT || "",  
        Notes: row.NOTES || "",
        StatusId: row.STATUS_ID,
        optionselected: row.action,
        BillingCode:row.New_Customer_Work_Code,
       
    }));
    
    const params = {
        jsonString: JSON.stringify(jsonPayload),
        optionselected: jsonPayload[0].optionselected
    };
    
    this.isLoading = true;
    
    DataService.UpdateRates(params)
        .then(res => {
            this.isLoading = false;
            
            if (res && res.data) {
                if (res.data.result === '1') {
                    this.ShowAlert(
                        this.$t("RecordUpdatedSuccessfully"),
                        "success",
                        true,
                        this.$t("Alert")
                    );
                    
                    this.RateScheduledeListing = this.RateScheduledeListing.filter(
                        row => !this.selectedRateIds.includes(row.RATE_SCHEDULE_ID)
                    );
                    
                    this.selectedRateIds = [];
                    this.isShownCopyButton = false;
                    
                    this.Headers.forEach(col => {
                        if (
                            col.COLUMN_NAME === "New_Start_Date" ||
                            col.COLUMN_NAME === "New_End_Date" ||
                            col.COLUMN_NAME === "New_Rate" ||
                            col.COLUMN_NAME === "comment" ||
                            col.COLUMN_NAME === "New_Customer_Work_Code"
                        ) {
                            col.VISIBLE = false;
                        }
                    });
                    
                    this.FetchData();
                    
                } 
                         else if (res.data.result === '-3') {
    const utilityList = utilityNames.join(', ');

    // Extract the overlap message from backend response
    const overlapMessage = res.data.msg; // "Overlap detected: Florida Power And Light (FPL)(J)02/11/2024 to 02/11/2026"
    
    // Extract the utility name and the date range from the overlap message
    const overlapDetails = overlapMessage.split('Overlap detected: ')[1]; // This will give the part after the prefix

    // Now format the final message correctly
    this.ShowAlert(
        `Rate for the following utilities already exists. Please change the date range for: ${overlapDetails}`,
        "alert-danger",
        true,
        "Date Overlap"
    );
}
                else if (res.data.result === '-2') {
                    this.ShowAlert(
                        res.data.msg || "Rate for utilities already exists. Please change date range.",
                        "warning",
                        true,
                        "Utility Overlap"
                    );
                }
                else {
                    this.ShowAlert(
                        res.data.msg || this.$t("UnknownError"),
                        "failure",
                        true,
                        this.$t("Alert")
                    );
                }
            } else {
                this.ShowAlert(
                    this.$t("UnknownError"),
                    "failure",
                    true,
                    this.$t("Alert")
                );
            }
        })
        .catch(error => {
            this.isLoading = false;
            console.error(error);
            
            this.ShowAlert(
                this.$t("UnknownError"),
                "failure",
                true,
                this.$t("Alert")
            );
        });
},

