handleCancel() {
    debugger;
    
    // If we're in copy/update mode, just reset the UI
    if (this.isShownCopyButton) {
        this.resetCopyUpdateMode();
        return;
    }
    
    // Otherwise, navigate back
    this.navigateBackToClient();
},

resetCopyUpdateMode() {
    debugger;
    
    // Clear selected rate IDs
    this.selectedRateIds = [];
    
    // Hide the copy/update button section
    this.isShownCopyButton = false;
    
    // Reset column visibility
    this.Headers.forEach(col => {
        if (
            col.COLUMN_NAME === "New_Start_Date" ||
            col.COLUMN_NAME === "New_End_Date" ||
            col.COLUMN_NAME === "New_Rate" ||
            col.COLUMN_NAME === "New_Customer_Work_Code" ||
            col.COLUMN_NAME === "comment"
        ) {
            col.VISIBLE = false;
        }
    });
    
    // Clear any temporary data
    this.RateScheduledeListing.forEach(row => {
        if (row.New_Start_Date) delete row.New_Start_Date;
        if (row.New_End_Date) delete row.New_End_Date;
        if (row.New_Rate) delete row.New_Rate;
        if (row.New_Customer_Work_Code) delete row.New_Customer_Work_Code;
        if (row.action) delete row.action;
    });
    
    // Restore search fields
    this.restoreSearchFields();
    
    // Force UI refresh
    this.refreshKey++;
