       leftCommonSearch: function (value) {
    debugger
    var vm = this;

    vm.PageNumber = value.PageNumber;
    vm.isPaged = 1;

    vm.searchByState = '';
    vm.searchByUtility = '';
    vm.workCodes = '';

    let searchCondition = '';
    if (typeof value.searchCondition !== 'undefined') {
        searchCondition = value.searchConditionJson && value.searchConditionJson !== ''
            ? value.searchConditionJson
            : value.searchCondition || "";
    }

    /* ================= MAP SEARCH VALUES ================= */
    if (searchCondition) {

        let params = new URLSearchParams(searchCondition);

        if (params.has('State')) {
            vm.searchByState = params.get('State');
        }

        if (params.has('UtilityName')) {
            vm.searchByUtility = params.get('UtilityName');
        }

        if (params.has('Workcode')) {
            vm.workCodes = params.get('Workcode');
        }

        vm.FetchData();
    } 
    else {
        vm.TotalRecords = 0;
        vm.PageNumber = 1;
        vm.refreshKey += 1;
         vm.FetchData();
    }
