DeleteData: function () {
    debugger
    var vm = this;
    var val = "";

    $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {
        if (val.length > 0)
            val += ',';
        val += $(this).val();
    });

    if (val.length > 0) {
        vm.confirmR(
            vm.$t("ConfirmDelete"),
            true,
            vm.$t("Delete") + " " + vm.$t("RateSchedule"),
            function () {

                let url = `ids=${val}&tableName=TALYGEN_BE_rate_schedule&primaryKey=RATE_SCHEDULE_ID`;

                DataService.Delete(url).then(response => {

                    if (response.data === "DeletedSuccess") {

                        let ids = val.split(',').map(Number);
                        vm.RateScheduledeListing = vm.RateScheduledeListing.filter(
                            x => !ids.includes(x.RATE_SCHEDULE_ID)
                        );

                        vm.ShowAlert(
                            vm.$t('DeletedSuccessfully'),
                            "success",
                            true,
                            vm.$t('Alert')
                        );

                    } else {
                        vm.ShowAlert(
                            vm.$t('DeletedError'),
                            "failure",
                            true,
                            vm.$t('Alert')
                        );
                    }

                
                });
            }
        );
    } else {
        vm.ShowAlert(
            vm.$t("Selectanyrecordtodelete"),
            "failure",
            true,
            vm.$t("Alert")
        );
    }
},

