        async FetchData() {
    debugger
    var vueObj = this;
    vueObj.isLoading = true; 
    
    
    const userDate = vueObj.getUserDate();
    var url = `clientId=${vueObj.clientId}&pageSize=${vueObj.pageSize}&pageNum=${vueObj.pageNum}&sortBy=${vueObj.sortBy}&sortExp=${vueObj.sortExp}&isBillingType=${vueObj.isBillingType}&clientIds=${vueObj.clientIds ?? ''}&workCodes=${vueObj.workCodes ?? ''}&searchByState=${vueObj.searchByState ?? ''}&searchByUtility=${vueObj.searchByUtility ?? ''}&userDate=${userDate}`;
    
    await DataService.GetWorkCodeMappingList(url).then(function (response) {
        debugger
        if (response.data != "" && response.data != null) {
            if (response.data.result.length > 0) {
                vueObj.RateScheduledeListing = response.data.result;
                vueObj.TotalRecords = response.data.result[0].TOTAL_RECORDS;
                vueObj.TotalPages = Math.ceil(vueObj.TotalRecords / vueObj.pageSize);
                vueObj.CurrentPage = vueObj.pageNum;
                vueObj.noRecord = false;
            } else {
                vueObj.noRecord = true;
                vueObj.TotalRecords = 0;
                vueObj.RateScheduledeListing = []; 
            }
        } else {
            vueObj.noRecord = true;
            vueObj.TotalRecords = 0;
            vueObj.RateScheduledeListing = []; 
        }
    }).catch(error => {
        vueObj.noRecord = true;
        vueObj.TotalRecords = 0;
        vueObj.RateScheduledeListing = []; 
    }).finally(() => {
        vueObj.isLoading = false; 
    });
},
        getUserDate() {
    const d = new Date();
    const year = d.getFullYear();
    const month = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`; // YYYY-MM-DD
},
