renderActions(row) {
    debugger;
    var self = this;
    let rtnActionArray = [];

    const isRecordSelected = row.isSelected;  

    self.listActions.forEach(actionItem => {
        let action = { ...actionItem };

        if (action.title === 'Edit') {
            action.isVisible = !isRecordSelected;
        }
        else if (action.title === 'EditDate') {
            action.isVisible = isRecordSelected;
        }

        if (action.isVisible !== false) {
            rtnActionArray.push(action);
        }
    });

    console.log("Rendered Actions: ", rtnActionArray);  // Debugging log to verify the returned actions

