handleDatesUpdated(updatedDates) {
  debugger;
  
  // STEP 1: Make columns visible first
  this.Headers.forEach(col => {
    if (col.COLUMN_NAME === "New_Start_Date" || col.COLUMN_NAME === "New_End_Date") {
      col.VISIBLE = true;
    }
  });
  
  // STEP 2: Update the data WITH formatted dates
  this.RateScheduledeListing.forEach((row, index) => {
    debugger
    if (this.selectedRateIds.includes(row.RATE_SCHEDULE_ID)) {
      if (updatedDates.startDate) {
        // Format the date using $options.filters.formatDate
        const formattedStartDate = this.$options.filters.formatDate(updatedDates.startDate);
        this.$set(this.RateScheduledeListing[index], 'New_Start_Date', formattedStartDate);
      }
      
      if (updatedDates.endDate) {
        // Format the date using $options.filters.formatDate
        const formattedEndDate = this.$options.filters.formatDate(updatedDates.endDate);
        this.$set(this.RateScheduledeListing[index], 'New_End_Date', formattedEndDate);
      }
    }
  });
  
  // STEP 3: Force UI update
  this.refreshKey++;
  
  // STEP 4: Close the modal AFTER updating
  this.isSetDate = false;
  this.EditData = []; // Clear edit data
},
